  "予知保全":{ fullName:"Predictive Maintenance", reading:"ヨチホゼン", cat:"AI・データ", rank:"A", impact:68, freq:"中", explanation:"壊れる前に故障を予想して先に対応すること。", example:"", value:"予知保全を知ると、設備や機器の故障を事前に予測するAI活用を提案でき、定期点検コストや突発停止による損失削減をROIとして試算できる。壊れてから直すのではなく、壊れる前に動くのが予知保全だ。", detail:"AI・データプロジェクトの仕様書・提案書に登場するキーワード。意味を知っていると、文書の読解精度が上がる。<br><span class='analogy-label'>💡 例え話：</span>予知保全は体調の変化を感じて早めに病院へ行くようなもの。症状が軽いうちに手を打つことで、大事に至らずに済む。" },
  "XAI":{ fullName:"Explainable AI", reading:"エックスエーアイ", cat:"AI・データ", rank:"A", impact:67, freq:"中", explanation:"AIがなぜそう答えたか説明しやすくする考え方。", example:"", value:"XAIを知ると、AIの判断に説明責任が求められる場面（融資審査・人事評価など）で「なぜそう判断したか」を示せる仕組みの重要性を語れる。XAIは「AIの言いなり」にならないための透明性の技術だ。", detail:"AI・データプロジェクトの仕様書・提案書に登場するキーワード。意味を知っていると、文書の読解精度が上がる。<br><span class='analogy-label'>💡 例え話：</span>XAIは判決に理由を添える判決文のようなもの。結論だけでなく、どんな根拠でその判断に至ったかを示す義務を果たす。" },
  "HITL":{ fullName:"Human In The Loop", reading:"ヒューマンインザループ", cat:"AIエージェント", rank:"A", impact:67, freq:"中", explanation:"AIの途中に人の確認を入れて安全にする仕組み。", example:"", value:"HITLを理解するとAIの強みと限界を正確に語れるようになり、エンジニアとの協働がスムーズになります。", detail:"生成AIを業務で活用するうえで知っておくべき仕組みのひとつ。知っているとAIツール選定・評価の場で的確な質問ができる。<br><span class='analogy-label'>💡 例え話：</span>HITLは「メガネのレンズ調整」のようなもの。適切に設定することで、AIの出力品質が格段にクリアになる。" },
  "トキシシティ":{ fullName:"Toxicity", reading:"トキシシティ", cat:"AIエージェント", rank:"A", impact:67, freq:"中", explanation:"AIが人を傷つける表現を出してしまう危険。", example:"", value:"トキシシティはAI関連の会議・提案書で頻出。知っているとAI活用の議論でリードできます。", detail:"トキシシティはAI活用の実務でよく出てくる概念。エンジニアや外部ベンダーとの会話でこの言葉が出たときに、すぐ文脈が読めると議論の質が上がる。<br><span class='analogy-label'>💡 例え話：</span>トキシシティは「レストランの注文伝票」のようなもの。正確に書けば書くほど、厨房（AI）が意図した料理を出してくれる。" },
  "バイアス":{ fullName:"Bias", reading:"バイアス", cat:"AI・データ", rank:"A", impact:67, freq:"中", explanation:"偏りのせいで判断が不公平になること。", example:"", value:"バイアスを知っているとデータ系プロジェクトの仕様書・提案書が正確に読めるようになります。", detail:"データドリブン経営を推進する際に理解が必要な概念。<br><span class='analogy-label'>💡 例え話：</span>バイアスは「カーナビの地図更新」のようなもの。古い地図（古いデータ）のままでは、正確な案内（意思決定）ができない。" },
  "プロンプトインジェクション":{ fullName:"Prompt Injection", reading:"プロンプトインジェクション", cat:"AIエージェント", rank:"A", impact:67, freq:"中", explanation:"悪い指示でAIのルールを崩そうとする攻撃。", example:"", value:"プロンプトインジェクションはAI関連の会議・提案書で頻出。知っているとAI活用の議論でリードできます。", detail:"プロンプトインジェクションはAI活用の実務でよく出てくる概念。エンジニアや外部ベンダーとの会話でこの言葉が出たときに、すぐ文脈が読めると議論の質が上がる。<br><span class='analogy-label'>💡 例え話：</span>プロンプトインジェクションは「レストランの注文伝票」のようなもの。正確に書けば書くほど、厨房（AI）が意図した料理を出してくれる。" },
  "プロンプト防御":{ fullName:"Prompt Defense", reading:"プロンプトボウギョ", cat:"AIエージェント", rank:"A", impact:67, freq:"中", explanation:"AIが危ない指示にだまされないよう守る対策。", example:"", value:"プロンプト防御を理解するとAIの強みと限界を正確に語れるようになり、エンジニアとの協働がスムーズになります。", detail:"生成AIを業務で活用するうえで知っておくべき仕組みのひとつ。知っているとAIツール選定・評価の場で的確な質問ができる。<br><span class='analogy-label'>💡 例え話：</span>プロンプト防御は「メガネのレンズ調整」のようなもの。適切に設定することで、AIの出力品質が格段にクリアになる。" },
  "レッドチーミング":{ fullName:"Red Teaming", reading:"レッドチーミング", cat:"AIエージェント", rank:"A", impact:66, freq:"中", explanation:"わざと意地悪な質問をして弱点を探す安全確認。", example:"", value:"レッドチーミングを知っていると、AI活用の提案書や報告書をより正確に読み・書けるようになります。", detail:"AI関連の提案書・報告書を読むときに必ず出てくる言葉。<br><span class='analogy-label'>💡 例え話：</span>レッドチーミングは「料理の下味」のようなもの。最初の段階で適切に仕込んでおくと、後の工程全体の質が底上げされる。" },
  "安全性":{ fullName:"Safety", reading:"アンゼンセイ", cat:"AIエージェント", rank:"A", impact:66, freq:"中", explanation:"AIが人や社会に危険を出さず使えること。", example:"", value:"安全性はAI関連の会議・提案書で頻出。知っているとAI活用の議論でリードできます。", detail:"安全性はAI活用の実務でよく出てくる概念。エンジニアや外部ベンダーとの会話でこの言葉が出たときに、すぐ文脈が読めると議論の質が上がる。<br><span class='analogy-label'>💡 例え話：</span>安全性は「レストランの注文伝票」のようなもの。正確に書けば書くほど、厨房（AI）が意図した料理を出してくれる。" },
  "透明性":{ fullName:"Transparency", reading:"トウメイセイ", cat:"AIエージェント", rank:"A", impact:66, freq:"中", explanation:"AIの仕組みや判断理由が見えやすいこと。", example:"", value:"透明性はAI関連の会議・提案書で頻出。知っているとAI活用の議論でリードできます。", detail:"透明性はAI活用の実務でよく出てくる概念。エンジニアや外部ベンダーとの会話でこの言葉が出たときに、すぐ文脈が読めると議論の質が上がる。<br><span class='analogy-label'>💡 例え話：</span>透明性は「レストランの注文伝票」のようなもの。正確に書けば書くほど、厨房（AI）が意図した料理を出してくれる。" },
